/*
This signal is emitted when change the value in profile. This is used to update key name in the [BoneMap] and to redraw the [BoneMap] editor.

Note: This signal is not connected directly to editor to simplify the reference, instead it is passed on to editor through the [BoneMap].

[BoneMap]: https://pkg.go.dev/graphics.gd/classdb/BoneMap
*/
func (self Instance) OnProfileUpdated(cb func(), flags ...Signal.Flags) Instance {
	var flags_together Signal.Flags
	for _, flag := range flags {
		flags_together |= flag
	}
	gd.ObjectConnect(self.AsObject()[0], gd.NewStringName("profile_updated"), gd.NewCallable(cb), int64(flags_together))
	return self
}

func (self class) ProfileUpdated() Signal.Any {
	return Signal.Via(gd.SignalProxy{}, pointers.Pack(gd.NewSignalOf(self.AsObject(), gd.NewStringName(`profile_updated`))))
}

